import{_ as e,o as t,c as p,j as a,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const h=JSON.parse('{"title":"青龙&朱雀","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/青龙&朱雀.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/青龙&朱雀.md"}'),b={name:"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/青龙&朱雀.md"};function o(d,r,_,l,m,i){return t(),p("div",null,[...r[0]||(r[0]=[a("h1",{id:"青龙-朱雀",tabindex:"-1"},[n("青龙&朱雀 "),a("a",{class:"header-anchor",href:"#青龙-朱雀","aria-label":'Permalink to "青龙&朱雀"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：新世短歌037")])])],-1),s('<h1 id="青龙-朱雀-1" tabindex="-1">青龙&amp;朱雀 <a class="header-anchor" href="#青龙-朱雀-1" aria-label="Permalink to &quot;青龙&amp;朱雀&quot;">​</a></h1><p>青龙&amp;朱雀<br> 价格：C+1500<br> 分类：武士刀，肋差<br> 武器伤害：11L<br> 武器特性：【破甲5/高速5】<br> 武器体积：3（青龙），2（朱雀）<br> 伤害类型：物理-挥砍<br> 描述：拥有双属性的武器，看起来像是锯齿一样的刀刃，有点吓人。附带冰与炎属性，攻击力和抗性都很优秀。<br> 效果：<br> 青龙&amp;朱雀是成对武器，这意味着你在购买朱雀&amp;青龙后，将会获得一把武士刀和一把肋差，分别名为【青龙】与【朱雀】，区别是前者具有的是【高速5】，后者为【破甲5】，在处理武器分类时肋差依旧可以作为武士刀使用。<br> 当你使用这对武器其中一把作为主要武器攻击时，可以将持有另外一把的基础属性一半与所有特性加入其中，但只有主要武器自带的破防能力正常生效（青龙对应高速，朱雀对应破甲）；你可以使用一个花招动作激活武器属性，此时若你使用的主要武器为青龙则该场景内这对武器伤害类型转为寒冷，若为朱雀则转为火焰。</p><p>【青龙&amp;朱雀可以作为两把武器处理，但在任何永久性导致武器损失/失去的效果中，青龙&amp;朱雀只能视为一把武器处理。】</p><p>绝影&amp;斩无<br> 价格：B+4000<br> 分类：武士刀，肋差<br> 武器伤害：18L<br> 武器特性：【幻灭】【高速6/破甲6】<br> 武器体积：3（绝影），2（斩无）<br> 伤害类型：物理-挥砍<br> 描述：双持武士刀，散发着强大的气场。如“断绝阴影、斩断虚无”一般，隐藏着能撕裂一切破坏力的双刀，并让使用者的速度飞跃性的提高。<br> 效果：<br> 绝影&amp;斩无是成对武器，这意味着你在购买绝影&amp;斩无后，将会获得一把武士刀和一把肋差，分别名为【绝影】与【斩无】，区别是前者具有的是【高速6】，后者为【破甲6】，在处理武器分类时肋差依旧可以作为武士刀使用。<br> 当你使用这对武器其中一把作为主要武器攻击时，可以将持有另外一把的基础属性一半与所有特性加入其中，但只有主要武器自带的破防能力正常生效（绝影对应高速，斩无对应破甲）；你可以使用一个自由动作并消费2点意志力激活武器属性，随后在该场景内，若你使用的主要武器为绝影则你的攻击具有【B级措手不及】，若为斩无则具有【接触攻击】特性。</p><p>【绝影&amp;斩无可以作为两把武器处理，但在任何永久性导致武器损失/失去的效果中，绝影&amp;斩无只能视为一把武器处理。】<br> 【特殊的是，该武器可由青龙&amp;朱雀差价购买获得，并替换青龙&amp;朱雀这一对武器。】</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const f=e(b,[["render",o]]);export{h as __pageData,f as default};
